#include <stdio.h>
#include <stdlib.h>

struct Node {
  int data;
  struct Node* next;
};

struct Stack {
  struct Node* top;
};

void push(struct Stack* stack, int data) {
  struct Node* new_node = (struct Node*)malloc(sizeof(struct Node));
  new_node->data = data;
  new_node->next = stack->top;
  stack->top = new_node;
}

int pop(struct Stack* stack) {
  if (stack->top == NULL) {
    printf("Stack boşdur\n");
    return -1;
  }
  struct Node* temp = stack->top;
  int data = temp->data;
  stack->top = temp->next;
  free(temp);
  return data;
}

void print_stack(struct Stack* stack) {
  struct Node* current = stack->top;
  printf("Stack: ");
  while (current != NULL) {
    printf("%d ", current->data);
    current = current->next;
  }
  printf("\n");
}

int main() {
  struct Stack stack = {NULL};
  push(&stack, 10);
  push(&stack, 20);
  push(&stack, 30);
  print_stack(&stack);
  printf("Pop: %d\n", pop(&stack));
  print_stack(&stack);
  return 0;
}
// Output:
// Stack: 30 20 10
// Pop: 30
// Stack: 20 10

